describe("formatLogEvent", () => {
  it("formats every log event type with non-empty text", () => {
    for (const type of ALL_LOG_EVENT_TYPES) {
      const line = formatLogEvent(dummyLogEvent(type, 3));

      if (silentLogEventTypes.has(type)) {
        expect(line).toBe("");
        continue;
